const usersRouter = require('./routes/users');

const app = express();
app.use(express.json());             // парсим JSON
app.use('/api/v1/users', usersRouter);

// централизованный обработчик ошибок (REST-friendly)
app.use((err, req, res, next) => {
  const status = err.status || 500;
  res.status(status).json({
    error: {
      message: err.message || 'Internal Server Error',
      details: err.details || undefined,
    },
  });
});

app.listen(3000, () => console.log('API on http://localhost:3000'));
"}]},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"routes/users.ts / routes/users.js"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"const express = require('express');
const router = express.Router();
const users = require('../services/users'); // “слой” работы с данными

// GET /api/v1/users?limit=10&offset=0&search=tim
router.get('/', async (req, res, next) => {
  try {
    const { limit = 10, offset = 0, search } = req.query;
    const result = await users.list({ limit: +limit, offset: +offset, search });
    res.json(result); // { items, total, limit, offset }
  } catch (e) { next(e); }
});

// GET /api/v1/users/:id
router.get('/:id', async (req, res, next) => {
  try {
    const user = await users.get(req.params.id);
    if (!user) return res.status(404).json({ error: { message: 'Not found' } });
    res.json(user);
  } catch (e) { next(e); }
});

// POST /api/v1/users
router.post('/', async (req, res, next) => {
  try {
    // в реальности: валидируем req.body!
    const created = await users.create(req.body);
    res.status(201)
       .location(`/api/v1/users/${created.id}`)
       .json(created);
  } catch (e) { next(e); }
});

// PATCH /api/v1/users/:id
router.patch('/:id', async (req, res, next) => {
  try {
    const updated = await users.update(req.params.id, req.body);
    if (!updated) return res.status(404).json({ error: { message: 'Not found' } });
    res.json(updated);
  } catch (e) { next(e); }
});

// DELETE /api/v1/users/:id
router.delete('/:id', async (req, res, next) => {
  try {
    const ok = await users.remove(req.params.id);
    if (!ok) return res.status(404).json({ error: { message: 'Not found' } });
    res.status(204).end();
  } catch (e) { next(e); }
});

module.exports = router;
"}]},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"services/users.ts / users.js (заглушка)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"let data = [];
let idSeq = 1;

module.exports = {
  async list({ limit, offset, search }) {
    let items = data;
    if (search) items = items.filter(u => u.name?.toLowerCase().includes(search.toLowerCase()));
    const total = items.length;
    return { items: items.slice(offset, offset + limit), total, limit, offset };
  },
  async get(id) { return data.find(u => String(u.id) === String(id)); },
  async create(dto) {
    const user = { id: idSeq++, ...dto, createdAt: new Date().toISOString() };
    data.push(user);
    return user;
  },
  async update(id, dto) {
    const idx = data.findIndex(u => String(u.id) === String(id));
    if (idx < 0) return null;
    data[idx] = { ...data[idx], ...dto, updatedAt: new Date().toISOString() };
    return data[idx];
  },
  async remove(id) {
    const before = data.length;
    data = data.filter(u => String(u.id) !== String(id));
    return data.length !== before;
