async function registerUser(data) {
  const exists = await userRepository.findByEmail(data.email);
  if (exists) throw new Error('EmailAlreadyUsed');
  const hashed = await hashPassword(data.password);
  const saved = await userRepository.save({ ...data, password: hashed });
  await mailService.sendWelcomeEmail(saved.email);
